/**
 * Unit Tests for Attribute Detection Stage
 *
 * TDD APPROACH: These tests are written FIRST and MUST FAIL before implementation.
 * They test all detector types, derived attributes, and edge cases.
 *
 * Tests cover:
 * - Pattern-based detection (regex_any, contains_any, starts_with)
 * - Derived attribute logic (self_sent, domain lookups)
 * - Error handling and edge cases
 * - Configuration validation
 * - Performance requirements
 */

import { AttributeDetectionStage } from '../../src/stages/attribute-detection';
import { EmailMessage, ProcessingConfig } from '../../src/types';

describe('AttributeDetectionStage', () => {
  let stage: AttributeDetectionStage;
  let mockConfig: ProcessingConfig;
  let mockEmailMessage: EmailMessage;

  beforeEach(() => {
    // Setup mock configuration matching real config structure
    mockConfig = {
      version: 2,
      taxonomy_notes: 'Test config',
      settings: {
        initialization: {
          apply_hard_assertions: true,
          seed_category_scores: true,
        },
        rule_scoring: {
          use_lexical_patterns: true,
          apply_subtype_rules: true,
          bounded_aggregation: true,
        },
        attribute_processing: {
          detect_self_sent: true,
          resolve_domains: true,
          derive_context_flags: true,
        },
        attribute_influence: {
          apply_bonuses: true,
          apply_penalties: true,
          enforce_caps: true,
        },
        disambiguation: {
          pairwise_adjustments: true,
          confidence_gap_threshold: 2,
        },
        multi_label_selection: {
          max_labels: 3,
          min_secondary_confidence: 8,
          allowed_combinations: ['financial+actionable'],
        },
        ai_routing: {
          high_confidence_threshold: 15,
          ai_required_threshold: 12,
          skip_ai_conditions: ['hard_assertion'],
        },
      },
      category_signals: {},
      confidence_thresholds: {
        high_confidence: 15,
        medium_confidence: 8,
        low_confidence: 3,
        ai_classification_required: 12,
        manual_review_required: 20,
        secondary_label_min_gap: 2,
      },
      multi_label_policy: {
        max_top_level_labels: 3,
        min_confidence_for_additional: 8,
        min_delta_primary_secondary: 2,
        allow_financial_actionable_copresence: true,
      },
      domain_signal_overrides: {},
      domain_signal_resolution: {
        mode: 'runtime_resolved',
        source: 'config/domain-sources.json',
        notes: 'Domain lists resolved at runtime',
      },
      top_level_categories: {},
      attributes: {
        schema: {
          urgency: {
            type: 'enum',
            values: ['low', 'medium', 'high'],
            description: 'Relative urgency derived from language & deadlines',
          },
          requires_action: {
            type: 'boolean',
            description: 'Email requires user action',
          },
          has_amount: {
            type: 'boolean',
            description: 'Email contains monetary amounts',
          },
          has_due_date: {
            type: 'boolean',
            description: 'Email contains due dates or deadlines',
          },
          tracking_present: {
            type: 'boolean',
            description: 'Email contains tracking information',
          },
          unsubscribe_present: {
            type: 'boolean',
            description: 'Email contains unsubscribe mechanism',
          },
        },
        detectors: [
          {
            attribute: 'has_amount',
            field: 'body',
            operation: 'regex_any',
            values: ['\\$\\d+', 'USD', 'amount due'],
          },
          {
            attribute: 'has_due_date',
            field: 'body',
            operation: 'contains_any',
            values: ['due by', 'due on', 'due date', 'pay by', 'payment due'],
          },
          {
            attribute: 'requires_action',
            field: 'body',
            operation: 'contains_any',
            values: ['please review', 'action required', 'respond', 'reply', 'follow up'],
          },
          {
            attribute: 'tracking_present',
            field: 'body',
            operation: 'contains_any',
            values: ['tracking number', 'track your package'],
          },
          {
            attribute: 'unsubscribe_present',
            field: 'body',
            operation: 'contains_any',
            values: ['unsubscribe', 'manage preferences'],
          },
          {
            attribute: 'requires_action',
            field: 'subject',
            operation: 'starts_with',
            values: ['ACTION REQUIRED', 'URGENT'],
          },
        ],
        derived: {
          self_sent: {
            logic: 'from_address in user_addresses AND all_recipients in user_addresses AND NOT list_id',
            notes: 'Email sent from user to self, excluding mailing lists',
          },
          from_financial_institution: {
            logic: 'from_domain in financial_domains OR from_domain in domain_lookup.financial',
            notes: 'Email from known financial institution',
          },
          from_newsletter_source: {
            logic: 'from_domain in newsletter_domains OR list_id header present',
            notes: 'Email from newsletter or mailing list source',
          },
          from_logistics_carrier: {
            logic: 'from_domain in logistics_domains',
            notes: 'Email from shipping/logistics carrier',
          },
        },
        attribute_bonus_map: {
          has_amount: {
            financial: 2,
            commerce_logistics: 1,
          },
          requires_action: {
            actionable: 3,
            financial: 1,
          },
          tracking_present: {
            commerce_logistics: 3,
            travel: 1,
          },
        },
      },
      attribute_relevance: {
        _roles_legend: {
          CORE: 'Essential for category, strong influence',
          PRIMARY_BOOST: 'High confidence boost',
          SECONDARY_BOOST: 'Moderate confidence boost',
          DISAMBIGUATOR: 'Helps resolve close calls',
          FILTER: 'Exclusion criteria',
          STRUCTURAL: 'Email structure metadata',
          DERIVED_LINK: 'Links to other derived attributes',
          NEUTRAL: 'No direct influence',
        },
        financial: {
          category_roles: {
            has_amount: 'PRIMARY_BOOST',
            from_financial_institution: 'CORE',
            requires_action: 'SECONDARY_BOOST',
          },
        },
        actionable: {
          category_roles: {
            requires_action: 'CORE',
            has_due_date: 'PRIMARY_BOOST',
          },
        },
      },
      ai_prompts: {
        feature_extraction: {
          system_prompt: ['Extract features from email'],
          user_prompt: ['Analyze this email: {email_content}'],
        },
        final_classification: {
          system_prompt: ['Classify email into categories'],
          user_prompt: ['Classify: {email_content}'],
        },
      },
      feature_extraction_schema: {
        type: 'object',
        properties: {
          urgency: { type: 'string', enum: ['low', 'medium', 'high'] },
          topics: { type: 'array', items: { type: 'string' } },
        },
        required: ['urgency'],
      },
    };

    // Setup mock email message
    mockEmailMessage = {
      id: 'test_email_123',
      threadId: 'thread_456',
      gmailLabels: ['INBOX'],
      payload: {
        mimeType: 'text/plain',
        headers: [
          { name: 'From', value: 'sender@example.com' },
          { name: 'To', value: 'user@gmail.com' },
          { name: 'Subject', value: 'Test Email' },
          { name: 'Date', value: 'Mon, 27 Sep 2025 10:00:00 +0000' },
        ],
        body: { data: 'VGVzdCBlbWFpbCBib2R5' }, // base64 encoded "Test email body"
      },
      subject: 'Test Email',
      from: { email: 'sender@example.com', name: 'Test Sender', raw: 'Test Sender <sender@example.com>' },
      to: [{ email: 'user@gmail.com', name: 'User', raw: 'User <user@gmail.com>' }],
      date: new Date('2025-09-27T10:00:00Z'),
      bodyPlain: 'Test email body',
      isProcessed: false,
      processingPriority: 50,
    };

    stage = new AttributeDetectionStage();
  });

  describe('Pattern-based Detection', () => {
    test('should detect has_amount attribute with regex patterns', async () => {
      const emailWithAmount = {
        ...mockEmailMessage,
        bodyPlain: 'Your invoice shows an amount due of $123.45 USD.',
        subject: 'Invoice Due',
      };

      const result = await stage.execute(emailWithAmount, mockConfig);

      expect(result.detected_attributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'has_amount',
          attribute_value: true,
          detection_method: 'pattern',
          detection_evidence: expect.stringContaining('$123.45'),
          confidence: expect.any(Number),
        })
      );
      expect(result.processing_duration_ms).toBeGreaterThan(0);
    });

    test('should detect has_due_date attribute with contains_any operation', async () => {
      const emailWithDueDate = {
        ...mockEmailMessage,
        bodyPlain: 'Payment is due by March 15th, 2025.',
        subject: 'Payment Reminder',
      };

      const result = await stage.execute(emailWithDueDate, mockConfig);

      expect(result.detected_attributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'has_due_date',
          attribute_value: true,
          detection_method: 'pattern',
          detection_evidence: expect.stringContaining('due by'),
        })
      );
    });

    test('should detect requires_action attribute from subject with starts_with operation', async () => {
      const emailWithActionSubject = {
        ...mockEmailMessage,
        subject: 'ACTION REQUIRED: Verify your account',
        bodyPlain: 'Please verify your account information.',
      };

      const result = await stage.execute(emailWithActionSubject, mockConfig);

      expect(result.detected_attributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'requires_action',
          attribute_value: true,
          detection_method: 'pattern',
          detection_evidence: expect.stringContaining('ACTION REQUIRED'),
        })
      );
    });

    test('should detect tracking_present attribute', async () => {
      const emailWithTracking = {
        ...mockEmailMessage,
        bodyPlain: 'Your package has shipped! Track your package with number 1Z123456789.',
        subject: 'Package Shipped',
      };

      const result = await stage.execute(emailWithTracking, mockConfig);

      expect(result.detected_attributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'tracking_present',
          attribute_value: true,
          detection_method: 'pattern',
        })
      );
    });

    test('should detect unsubscribe_present attribute', async () => {
      const emailWithUnsubscribe = {
        ...mockEmailMessage,
        bodyPlain: 'Weekly newsletter content. To unsubscribe, click here.',
        subject: 'Weekly Newsletter',
      };

      const result = await stage.execute(emailWithUnsubscribe, mockConfig);

      expect(result.detected_attributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'unsubscribe_present',
          attribute_value: true,
          detection_method: 'pattern',
        })
      );
    });

    test('should handle multiple pattern matches for same attribute', async () => {
      const emailWithMultipleAmounts = {
        ...mockEmailMessage,
        bodyPlain: 'Invoice total: $50.00 USD. Amount due: $25.00. Previous balance was $25.00.',
        subject: 'Invoice Statement',
      };

      const result = await stage.execute(emailWithMultipleAmounts, mockConfig);

      const amountAttribute = result.detected_attributes.find((attr) => attr.attribute_name === 'has_amount');
      expect(amountAttribute).toBeDefined();
      expect(amountAttribute?.detection_evidence).toMatch(/\$\d+/);
    });

    test('should be case insensitive for pattern matching', async () => {
      const emailCaseInsensitive = {
        ...mockEmailMessage,
        bodyPlain: 'PAYMENT DUE BY MARCH 15TH',
        subject: 'URGENT PAYMENT NOTICE',
      };

      const result = await stage.execute(emailCaseInsensitive, mockConfig);

      expect(result.detected_attributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'has_due_date',
          attribute_value: true,
        })
      );
    });
  });

  describe('Derived Attributes', () => {
    test('should detect self_sent attribute for user-to-user emails', async () => {
      const selfSentEmail = {
        ...mockEmailMessage,
        from: { email: 'user@gmail.com', name: 'User', raw: 'User <user@gmail.com>' },
        to: [{ email: 'user@gmail.com', name: 'User', raw: 'User <user@gmail.com>' }],
        subject: 'Reminder to self',
        bodyPlain: 'Don\'t forget to call dentist',
      };

      // Mock user addresses method
      jest.spyOn(stage, '_getUserAddresses' as keyof AttributeDetectionStage).mockReturnValue(['user@gmail.com']);

      const result = await stage.execute(selfSentEmail, mockConfig);

      expect(result.detected_attributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'self_sent',
          attribute_value: true,
          detection_method: 'derived',
          detection_evidence: expect.stringContaining('user addresses'),
        })
      );
    });

    test('should NOT detect self_sent when List-Id header present', async () => {
      const mailingListEmail = {
        ...mockEmailMessage,
        from: { email: 'user@gmail.com', name: 'User', raw: 'User <user@gmail.com>' },
        to: [{ email: 'user@gmail.com', name: 'User', raw: 'User <user@gmail.com>' }],
        payload: {
          ...mockEmailMessage.payload,
          headers: [...mockEmailMessage.payload.headers, { name: 'List-Id', value: '<newsletter.example.com>' }],
        },
      };

      jest.spyOn(stage, '_getUserAddresses' as keyof AttributeDetectionStage).mockReturnValue(['user@gmail.com']);

      const result = await stage.execute(mailingListEmail, mockConfig);

      const selfSentAttribute = result.detected_attributes.find((attr) => attr.attribute_name === 'self_sent');
      expect(selfSentAttribute).toBeUndefined();
    });

    test('should detect from_financial_institution from domain lookup', async () => {
      const financialEmail = {
        ...mockEmailMessage,
        from: { email: 'statements@chase.com', name: 'Chase Bank', raw: 'Chase Bank <statements@chase.com>' },
        subject: 'Monthly Statement',
        bodyPlain: 'Your monthly statement is ready',
      };

      // Mock domain lookup
      jest.spyOn(stage as any, '_getFinancialDomains').mockReturnValue(['chase.com', 'bankofamerica.com']);

      const result = await stage.execute(financialEmail, mockConfig);

      expect(result.detected_attributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'from_financial_institution',
          attribute_value: true,
          detection_method: 'domain_lookup',
          detection_evidence: 'chase.com',
        })
      );
    });

    test('should detect from_newsletter_source from domain or List-Id', async () => {
      const newsletterEmail = {
        ...mockEmailMessage,
        from: { email: 'newsletter@medium.com', name: 'Medium', raw: 'Medium <newsletter@medium.com>' },
        payload: {
          ...mockEmailMessage.payload,
          headers: [...mockEmailMessage.payload.headers, { name: 'List-Id', value: '<digest.medium.com>' }],
        },
      };

      jest.spyOn(stage as any, '_getNewsletterDomains').mockReturnValue(['medium.com', 'substack.com']);

      const result = await stage.execute(newsletterEmail, mockConfig);

      expect(result.detected_attributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'from_newsletter_source',
          attribute_value: true,
          detection_method: expect.stringMatching(/domain_lookup|derived/),
        })
      );
    });

    test('should detect from_logistics_carrier', async () => {
      const logisticsEmail = {
        ...mockEmailMessage,
        from: { email: 'tracking@fedex.com', name: 'FedEx', raw: 'FedEx <tracking@fedex.com>' },
        subject: 'Package Delivered',
        bodyPlain: 'Your package has been delivered',
      };

      jest.spyOn(stage as any, '_getLogisticsDomains').mockReturnValue(['fedex.com', 'ups.com', 'usps.com']);

      const result = await stage.execute(logisticsEmail, mockConfig);

      expect(result.detected_attributes).toContainEqual(
        expect.objectContaining({
          attribute_name: 'from_logistics_carrier',
          attribute_value: true,
          detection_method: 'domain_lookup',
        })
      );
    });
  });

  describe('Configuration Settings', () => {
    test('should respect detect_self_sent setting when disabled', async () => {
      const configNoSelfSent = {
        ...mockConfig,
        settings: {
          ...mockConfig.settings,
          attribute_processing: {
            ...mockConfig.settings.attribute_processing,
            detect_self_sent: false,
          },
        },
      };

      const selfSentEmail = {
        ...mockEmailMessage,
        from: { email: 'user@gmail.com', name: 'User', raw: 'User <user@gmail.com>' },
        to: [{ email: 'user@gmail.com', name: 'User', raw: 'User <user@gmail.com>' }],
      };

      jest.spyOn(stage, '_getUserAddresses' as keyof AttributeDetectionStage).mockReturnValue(['user@gmail.com']);

      const result = await stage.execute(selfSentEmail, configNoSelfSent);

      const selfSentAttribute = result.detected_attributes.find((attr) => attr.attribute_name === 'self_sent');
      expect(selfSentAttribute).toBeUndefined();
    });

    test('should respect resolve_domains setting when disabled', async () => {
      const configNoDomains = {
        ...mockConfig,
        settings: {
          ...mockConfig.settings,
          attribute_processing: {
            ...mockConfig.settings.attribute_processing,
            resolve_domains: false,
          },
        },
      };

      const financialEmail = {
        ...mockEmailMessage,
        from: { email: 'statements@chase.com', name: 'Chase Bank', raw: 'Chase Bank <statements@chase.com>' },
      };

      jest.spyOn(stage as any, '_getFinancialDomains').mockReturnValue(['chase.com']);

      const result = await stage.execute(financialEmail, configNoDomains);

      const financialAttribute = result.detected_attributes.find(
        (attr) => attr.attribute_name === 'from_financial_institution'
      );
      expect(financialAttribute).toBeUndefined();
    });
  });

  describe('Edge Cases and Error Handling', () => {
    test('should handle missing email content gracefully', async () => {
      const emailNoContent = {
        ...mockEmailMessage,
        bodyPlain: undefined,
        subject: '',
      };

      const result = await stage.execute(emailNoContent, mockConfig);

      expect(result.detected_attributes).toEqual([]);
      expect(result.errors).toBeUndefined();
    });

    test('should handle malformed from address', async () => {
      const emailMalformedFrom = {
        ...mockEmailMessage,
        from: { email: 'invalid-email', name: 'Invalid', raw: 'invalid-email' },
      };

      const result = await stage.execute(emailMalformedFrom, mockConfig);

      // Should not crash, should continue processing
      expect(result).toBeDefined();
      expect(result.detected_attributes).toBeDefined();
    });

    test('should handle empty detector configuration', async () => {
      const configNoDetectors = {
        ...mockConfig,
        attributes: {
          ...mockConfig.attributes,
          detectors: [],
        },
      };

      const result = await stage.execute(mockEmailMessage, configNoDetectors);

      expect(result.detected_attributes).toEqual([]);
    });

    test('should handle unknown field types in detectors', async () => {
      const configBadField = {
        ...mockConfig,
        attributes: {
          ...mockConfig.attributes,
          detectors: [
            {
              attribute: 'test_attr',
              field: 'unknown_field',
              operation: 'contains_any',
              values: ['test'],
            },
          ],
        },
      };

      const result = await stage.execute(mockEmailMessage, configBadField);

      // Should not include the attribute with unknown field
      const testAttribute = result.detected_attributes.find((attr) => attr.attribute_name === 'test_attr');
      expect(testAttribute).toBeUndefined();
    });

    test('should handle unknown operations in detectors', async () => {
      const configBadOperation = {
        ...mockConfig,
        attributes: {
          ...mockConfig.attributes,
          detectors: [
            {
              attribute: 'test_attr',
              field: 'body',
              operation: 'unknown_operation',
              values: ['test'],
            },
          ],
        },
      };

      const result = await stage.execute(mockEmailMessage, configBadOperation);

      // Should not include the attribute with unknown operation
      const testAttribute = result.detected_attributes.find((attr) => attr.attribute_name === 'test_attr');
      expect(testAttribute).toBeUndefined();
    });

    test('should handle invalid regex patterns gracefully', async () => {
      const configInvalidRegex = {
        ...mockConfig,
        attributes: {
          ...mockConfig.attributes,
          detectors: [
            {
              attribute: 'test_attr',
              field: 'body',
              operation: 'regex_any',
              values: ['[invalid regex'], // Missing closing bracket
            },
          ],
        },
      };

      const result = await stage.execute(mockEmailMessage, configInvalidRegex);

      // Should handle invalid regex gracefully
      expect(result).toBeDefined();
      expect(result.detected_attributes).toBeDefined();
    });
  });

  describe('Performance Requirements', () => {
    test('should complete processing within reasonable time', async () => {
      const startTime = Date.now();

      const result = await stage.execute(mockEmailMessage, mockConfig);

      const endTime = Date.now();
      const processingTime = endTime - startTime;

      expect(processingTime).toBeLessThan(1000); // Should complete within 1 second
      expect(result.processing_duration_ms).toBeGreaterThan(0);
      expect(result.processing_duration_ms).toBeLessThan(1000);
    });

    test('should handle batch processing efficiently', async () => {
      const emails = Array(10)
        .fill(null)
        .map((_, i) => ({
          ...mockEmailMessage,
          id: `test_email_${i}`,
          bodyPlain: `Test email body with amount $${i * 10}.00`,
        }));

      const startTime = Date.now();

      const results = await Promise.all(emails.map((email) => stage.execute(email, mockConfig)));

      const endTime = Date.now();
      const totalTime = endTime - startTime;

      expect(results).toHaveLength(10);
      expect(totalTime).toBeLessThan(5000); // 10 emails in under 5 seconds

      // Each email should have detected has_amount
      results.forEach((result, _i) => {
        expect(result.detected_attributes).toContainEqual(
          expect.objectContaining({
            attribute_name: 'has_amount',
            attribute_value: true,
          })
        );
      });
    });
  });

  describe('Parallel Processing Support', () => {
    test('should support parallel processing metadata', async () => {
      const result = await stage.execute(mockEmailMessage, mockConfig);

      expect(result).toHaveProperty('parallel_processed');
      expect(result).toHaveProperty('dependencies');
      expect(Array.isArray(result.dependencies)).toBe(true);
    });

    test('should provide detection metadata for debugging', async () => {
      const emailWithAttributes = {
        ...mockEmailMessage,
        bodyPlain: 'Invoice $100 due by March 15th. Please review and reply.',
        subject: 'ACTION REQUIRED: Payment Due',
      };

      const result = await stage.execute(emailWithAttributes, mockConfig);

      // Should have multiple detected attributes
      expect(result.detected_attributes.length).toBeGreaterThan(1);

      result.detected_attributes.forEach((attr) => {
        expect(attr).toHaveProperty('attribute_name');
        expect(attr).toHaveProperty('attribute_value');
        expect(attr).toHaveProperty('detection_method');
        expect(attr).toHaveProperty('detection_evidence');
        expect(attr).toHaveProperty('confidence');
        expect(typeof attr.confidence).toBe('number');
        expect(attr.confidence).toBeGreaterThanOrEqual(0);
        expect(attr.confidence).toBeLessThanOrEqual(1);
      });
    });
  });

  describe('Integration with Previous Stages', () => {
    test('should handle input from rule scoring stage', async () => {
      const emailWithPreviousStageData = {
        ...mockEmailMessage,
        // Simulate data from previous stages
        candidate_scores: {
          financial: 5,
          actionable: 3,
        },
        stage_results: [
          { stage: 'hard_assertions', completed: true },
          { stage: 'strong_indicators', completed: true },
          { stage: 'rule_scoring', completed: true },
        ],
      };

      const result = await stage.execute(emailWithPreviousStageData, mockConfig);

      expect(result).toBeDefined();
      expect(result.detected_attributes).toBeDefined();

      // Should preserve previous stage data
      expect(result).toHaveProperty('candidate_scores');
      expect(result).toHaveProperty('stage_results');
    });
  });
});

