/**
 * API types for Classification Engine REST endpoints
 *
 * These types match the OpenAPI specification and are used by contract tests.
 * They bridge between the Gmail API payload format and our internal types.
 */

import { EmailMessage, EmailClassification, ExplainabilityTrace } from './index';

/**
 * EmailContent - Simplified version of EmailMessage for API requests
 * Maps to EmailMessage but with optional fields for API flexibility
 */
export interface EmailContent {
  id: string;
  threadId: string;
  subject: string;
  from: {
    email: string;
    name?: string;
    raw: string;
  };
  to: Array<{
    email: string;
    name?: string;
    raw: string;
  }>;
  cc?: Array<{
    email: string;
    name?: string;
    raw: string;
  }>;
  bcc?: Array<{
    email: string;
    name?: string;
    raw: string;
  }>;
  date: Date;
  bodyPlain?: string;
  bodyHtml?: string;
  headers: Array<{
    name: string;
    value: string;
  }>;

  // Gmail API specific fields
  snippet?: string;
  historyId?: string;
  sizeEstimate?: number;
}

/**
 * Request for batch classification endpoint
 */
export interface BatchClassificationRequest {
  emails: EmailContent[];
  sessionId: string;
  processingMode?: 'parallel' | 'sequential';
  configVersion?: string;
}

/**
 * Response from batch classification endpoint
 */
export interface BatchClassificationResponse {
  sessionId: string;
  processedCount: number;
  successCount: number;
  errorCount: number;
  results: BatchClassificationResult[];
  performance: {
    totalDurationMs: number;
    avgEmailDurationMs: number;
    parallelStagesUsed: boolean;
  };
  errors?: ClassificationError[];
}

/**
 * Individual classification result in batch response
 */
export interface BatchClassificationResult {
  emailId: string;
  classification: EmailClassification;
  explainabilityTrace?: ExplainabilityTrace;
  processingDurationMs: number;
  success: boolean;
  error?: string;
}

/**
 * Request for single email classification endpoint
 */
export interface SingleClassificationRequest {
  email: EmailContent;
  sessionId: string;
  includeExplainability?: boolean;
  configVersion?: string;
}

/**
 * Response from single email classification endpoint
 */
export interface SingleClassificationResponse {
  sessionId: string;
  emailId: string;
  classification: EmailClassification;
  explainabilityTrace?: ExplainabilityTrace;
  processingDurationMs: number;
  configVersion: string;
}

/**
 * Request for configuration validation endpoint
 */
export interface ConfigValidationRequest {
  configuration: any; // Flexible to allow invalid configs in tests
  validateAgainstSchema?: boolean;
  generateCompiledRules?: boolean;
}

/**
 * Response from configuration validation endpoint
 */
export interface ConfigValidationResponse {
  valid: boolean;
  errors: ValidationError[];
  warnings: ValidationWarning[];
  compiledRules?: CompiledRule[];
  compilationMetrics?: {
    rulesGenerated: number;
    optimizationsApplied: number;
    compilationDurationMs: number;
  };
}

/**
 * Validation error details
 */
export interface ValidationError {
  path: string;
  message: string;
  code: string;
  severity: 'error' | 'warning';
}

/**
 * Validation warning details
 */
export interface ValidationWarning {
  path: string;
  message: string;
  suggestion?: string;
}

/**
 * Compiled rule for performance optimization
 */
export interface CompiledRule {
  id: string;
  category: string;
  subtype?: string;
  pattern: RegExp;
  weight: number;
  tier: 'high' | 'medium' | 'low';
}

/**
 * Classification error details
 */
export interface ClassificationError {
  emailId: string;
  stage: string;
  error: string;
  timestamp: Date;
  recoverable: boolean;
}

